import React from "react";
import { ArrowLeft, ArrowUpRight, ArrowDownLeft, Download } from "lucide-react";
import { formatCurrency } from "../helpers/helpers";

export default function TransactionHistoryScreen({ transactions = [], onBack, onSelectTransaction, darkMode }) {
  return (
    <div className={`min-h-screen px-6 pt-6 pb-24 ${darkMode ? "bg-gray-900 text-white" : "bg-gray-50 text-gray-900"}`}>

      {/* Header */}
      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center gap-3">
          <button onClick={onBack}>
            <ArrowLeft className={`w-6 h-6 ${darkMode ? "text-white" : "text-gray-700"}`} />
          </button>
          <h1 className="text-xl font-semibold">Transactions</h1>
        </div>

        <button className="p-2 rounded-lg active:scale-95 transition">
          <Download className={`w-5 h-5 ${darkMode ? "text-white" : "text-gray-700"}`} />
        </button>
      </div>

      {/* Transaction List */}
      <div className="space-y-4">
        {transactions.map((tx) => {
          const isDeposit = tx.type.toLowerCase().includes("deposit");
          return (
            <div
              key={tx.id}
              onClick={() => onSelectTransaction(tx)}
              className={`flex items-center justify-between p-3 rounded-xl border cursor-pointer transition ${
                darkMode ? "bg-gray-800 border-gray-700 hover:bg-gray-700" : "bg-white border-gray-50 hover:bg-gray-50"
              }`}
            >
              <div className="flex items-center gap-3">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center ${
                  isDeposit ? "bg-emerald-100 text-emerald-600" : "bg-red-100 text-red-600"
                }`}>
                  {isDeposit ? <ArrowDownLeft className="w-5 h-5" /> : <ArrowUpRight className="w-5 h-5" />}
                </div>

                <div>
                  <p className={`${darkMode ? "text-white" : "text-gray-800"} font-semibold`}>
                    {tx.title}
                  </p>
                  <p className={`${darkMode ? "text-gray-400" : "text-gray-400"} text-xs`}>
                    {tx.date}
                  </p>
                </div>
              </div>

              <span className={`font-bold text-sm ${isDeposit ? "text-emerald-600" : darkMode ? "text-white" : "text-gray-800"}`}>
                {isDeposit ? "+" : "-"}₦{formatCurrency(tx.amount)}
              </span>
            </div>
          );
        })}
      </div>
    </div>
  );
}
